import{_ as a,o as t,c as r,a3 as o}from"./chunks/framework.CjquFG0V.js";const u=JSON.parse('{"title":"53. Purchased Leave","description":"","frontmatter":{"title":"53. Purchased Leave","eba":"Biomedical Engineers 2025-2028","topics":["leave","wages","employment"]},"headers":[],"relativePath":"ebas/biomedical-engineers/leave/53-purchased-leave.md","filePath":"ebas/biomedical-engineers/leave/53-purchased-leave.md"}'),n={name:"ebas/biomedical-engineers/leave/53-purchased-leave.md"};function s(p,e,l,d,i,h){return t(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="_53-purchased-leave" tabindex="-1">53. Purchased Leave <a class="header-anchor" href="#_53-purchased-leave" aria-label="Permalink to &quot;53. Purchased Leave&quot;">​</a></h1><p>This clause does not apply to casual Employees.</p><p><strong>53.1</strong> An Employee may apply to purchase up to 20 working days (pro-rated for part-time Employees) additional paid leave in a twelve-month period at ordinary pay.</p><p><strong>53.2</strong> The additional paid leave is purchased through salary deductions made over the whole year. The amount deducted will correspond with the amount of leave purchased.</p><p>Example 1: An Employee who purchases an additional four (4) weeks leave will be paid 48/52 or 92.31% of their ordinary pay throughout the relevant 12 month period. Example 2: An Employee who purchases an additional two (2) weeks leave will be paid 50/52 or 96.15% of their ordinary pay throughout the relevant 12 month period.</p><p><strong>53.3</strong> Purchased Leave may be taken in conjunction with other types of leave.</p><p><strong>53.4</strong> Purchased Leave must be used in the twelve-month period in which it is purchased.</p><p><strong>53.5</strong> Purchased leave will be taken at a time that is mutually agreed between the Employer and the Employee.</p><p><strong>53.6</strong> Once approval has been granted, the Employee may only vary or cancel the arrangement in extraordinary circumstances.</p><p><strong>53.7</strong> Where the:</p><p><strong>(a)</strong> arrangement has been varied or cancelled because of extraordinary circumstances;</p><p><strong>(b)</strong> Employee’s employment terminates; or</p><p><strong>(c)</strong> purchased leave has not been taken in the relevant 12-month period; the Employer will refund the amount of salary deducted in respect of any unused purchased leave as a lump sum.</p><p><strong>53.8</strong> Where the Employee’s employment terminates and the amount of purchased leave taken exceeds the amount deducted, the Employer may deduct a sum equal to the negative balance from any remuneration payable to the Employee upon termination of employment.</p><p><strong>53.9</strong> Purchased leave:</p><p><strong>(a)</strong> counts as service for all purposes; and</p><p><strong>(b)</strong> is not annual leave.</p>',17)])])}const m=a(n,[["render",s]]);export{u as __pageData,m as default};
